// ===== Warehouse Bot — full logic (Telegram bot + Mini App API) =====
// כל ההגדרות כאן:
const GAS_URL    = "https://script.google.com/macros/s/AKfycbyWbitZm_uLgVJ3T32c7rRYKogUpeO3lRJXeW7yvxNxwPfolnItm81pFXUWgo_Cugh_WA/exec";
const SECRET     = "5df5fb11434ea8be13b320ddd7d797d51d1473d43bd11a8f";
const BOT_TOKEN  = "8842770819:AAGX2uOJsrXbAoomle99LNu7q6Qtj4k0UKM";
// כתובת ה-Mini App (Render static) — לכפתורים ולתמונות האריה:
const MINIAPP_URL = ($env && $env.MINIAPP_URL) || "https://smartsys.onrender.com";

const TG_API = `https://api.telegram.org/bot${BOT_TOKEN}`;
const crypto = require("crypto");
const http = (opts) => this.helpers.httpRequest(opts);

const LION = {
  smile:   `${MINIAPP_URL}/lion_smile.png`,
  grin:    `${MINIAPP_URL}/lion_grin.png`,
  wink:    `${MINIAPP_URL}/lion_wink.png`,
  neutral: `${MINIAPP_URL}/lion_neutral.png`,
};

const gas = async (action, payload) => {
  const res = await http({ method:"POST", url:GAS_URL,
    body:{ secret:SECRET, action, payload: payload||{} }, json:true });
  if (!res || !res.ok) throw new Error((res && res.error) || "gas error");
  return res.data;
};
const tg = (method, payload) =>
  http({ method:"POST", url:`${TG_API}/${method}`, body:payload, json:true });

const appButton = () => ({ inline_keyboard: [[{ text:"🦁 פתח מחסן", web_app:{ url: MINIAPP_URL } }]] });
const sendText = (chat_id, text, btn) =>
  tg("sendMessage", { chat_id, text, ...(btn ? { reply_markup: appButton() } : {}) });
const sendPhoto = async (chat_id, photo, caption, btn) => {
  try { return await tg("sendPhoto", { chat_id, photo, caption, parse_mode:"HTML",
    ...(btn ? { reply_markup: appButton() } : {}) }); }
  catch (e) { return sendText(chat_id, caption, btn); }
};

const checkInitData = (initData) => {
  if (!initData) return null;
  const p = new URLSearchParams(initData);
  const hash = p.get("hash"); if (!hash) return null;
  p.delete("hash");
  const dcs = [...p.entries()].map(([k,v]) => `${k}=${v}`).sort().join("\n");
  const sk = crypto.createHmac("sha256","WebAppData").update(BOT_TOKEN).digest();
  const calc = crypto.createHmac("sha256", sk).update(dcs).digest("hex");
  if (calc !== hash) return null;
  try { return JSON.parse(p.get("user")||"null"); } catch { return null; }
};
const roleOf = async (user) => {
  if (!user) return null;
  const cfg = await gas("getConfig");
  const id = String(user.id);
  if (String(cfg.managerChatId) === id) return "manager";
  if (String(cfg.warehouseChatId) === id) return "warehouse";
  return null;
};
const regReply = (role, r) => {
  const who = role === "manager" ? "מנהל" : "מחסן";
  switch (r.status) {
    case "registered":  return `✅ הוגדרת כ${who}.\nchat id: ${r.chatId}`;
    case "replaced":    return `✅ הוחלף — הוגדרת כ${who}.\nchat id: ${r.chatId}`;
    case "already_you": return `כבר רשום כ${who} ✓\nchat id: ${r.chatId}`;
    case "locked":      return `🔒 תפקיד ה${who} כבר תפוס.\nכדי להחליף: פתח allowRegister=TRUE בגיליון ושלח שוב.`;
    case "bot_register_off": return `🚫 רישום דרך הבוט חסום. ניהול ידני בגיליון.`;
    default: return "שגיאת רישום.";
  }
};

const reply = (obj) => [{ json: { responseBody: obj } }];

const inItem  = $input.first().json;
const body    = inItem.body || {};
const headers = inItem.headers || {};

// =================== TELEGRAM ===================
if (body.update_id !== undefined) {
  const msg = body.message || body.edited_message;
  if (msg && msg.text) {
    const chatId = msg.chat.id;
    const text = msg.text.trim();
    const cfg = await gas("getConfig");
    const isManager = String(cfg.managerChatId) === String(chatId);

    if (text.startsWith("/start")) {
      await sendPhoto(chatId, LION.neutral, "היי בוס 🦁\nברוך הבא לבוט המחסן.\nלפתיחה לחץ למטה 👇", true);
    } else if (text.startsWith("/iammanager")) {
      const r = await gas("registerRole", { role:"manager", chatId:String(chatId) });
      await sendText(chatId, regReply("manager", r));
    } else if (text.startsWith("/iamwarehouse")) {
      const r = await gas("registerRole", { role:"warehouse", chatId:String(chatId) });
      await sendText(chatId, regReply("warehouse", r));
    } else if (text.startsWith("/status")) {
      if (!isManager) { await sendText(chatId, "❌ פקודה למנהל בלבד."); }
      else await sendText(chatId, `מצב רישום:\nמנהל: ${cfg.managerChatId||"—"}\nמחסן: ${cfg.warehouseChatId||"—"}\nרישום בוט: ${cfg.botRegister}\nמתג החלפה: ${cfg.allowRegister}`);
    } else if (text.startsWith("/reset")) {
      if (!isManager) { await sendText(chatId, "❌ פקודה למנהל בלבד."); }
      else {
        const part = text.split(/\s+/)[1];
        if (part === "manager" || part === "warehouse") {
          await gas("resetRole", { role: part });
          await sendText(chatId, `♻️ תפקיד ${part} אופס. פתח allowRegister=TRUE ושלח /iam${part} מהחשבון החדש.`);
        } else await sendText(chatId, "שימוש: /reset manager  או  /reset warehouse");
      }
    } else if (text.startsWith("/whoami")) {
      await sendText(chatId, `chat id: ${chatId}`);
    } else {
      await sendText(chatId, "לפתיחת המחסן 👇", true);
    }
  }
  return reply({ ok:true });
}

// =================== MINI APP API ===================
// הבקשה מהאפליקציה: { action, payload, initData }  (או X-Init-Data בכותרת)
const action   = (body.action || "").toString();
const payload  = body.payload || {};
const initData = headers["x-init-data"] || body.initData || "";

if (action === "catalog") {
  const data = await gas("getCatalog");
  return reply({ ok:true, products:data.products, packTypes:data.packTypes });
}

const user = checkInitData(initData);
if (!user) return reply({ ok:false, error:"unauthorized" });
const role = await roleOf(user);
if (!role) return reply({ ok:false, error:"unauthorized" });

if (action === "me")
  return reply({ ok:true, role, name: user.first_name || "" });

if (action === "listOrders") {
  const orders = await gas("listOrders", { status: payload.status || "" });
  return reply({ ok:true, orders });
}

if (action === "createOrder") {
  if (role !== "manager") return reply({ ok:false, error:"unauthorized" });
  const order = await gas("createOrder", { ...payload.order, createdBy: user.first_name || "" });
  const cfg = await gas("getConfig");
  if (cfg.warehouseChatId)
    await sendPhoto(cfg.warehouseChatId, LION.smile, `📦 <b>הזמנה חדשה #${order.orderNo}</b>\nפתח את המחסן כדי לצפות ולאשר.`, true);
  return reply({ ok:true, order });
}

if (action === "confirmOrder") {
  if (role !== "warehouse") return reply({ ok:false, error:"unauthorized" });
  const order = await gas("confirmOrder", { orderNo: payload.orderNo, confirmedBy: user.first_name || "" });
  const cfg = await gas("getConfig");
  if (cfg.managerChatId)
    await sendPhoto(cfg.managerChatId, LION.grin, `🎉 <b>הזמנה #${order.orderNo} מוכנה לאיסוף!</b>`, false);
  return reply({ ok:true, order });
}

if (action === "editOrder") {
  if (role !== "manager") return reply({ ok:false, error:"unauthorized" });
  const order = await gas("editOrder", { orderNo: payload.orderNo, fields: payload.fields || {} });
  const cfg = await gas("getConfig");
  if (cfg.warehouseChatId)
    await sendPhoto(cfg.warehouseChatId, LION.wink, `🔄 <b>הזמנה #${order.orderNo} עודכנה</b> ע״י המנהל.`, true);
  return reply({ ok:true, order });
}

return reply({ ok:false, error:"unknown action: " + action });

const userMessage = $('Telegram Trigger').item.json.message.text;
const chatId = $('Telegram Trigger').item.json.message.chat.id;

let registry = [];
try {
  const items = $('Read Registry').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) registry = first;
    else if (Array.isArray(first.agents)) registry = first.agents;
    else registry = items.map(i => i.json);
  }
} catch(e) {}

let memory = [];
try {
  const items = $('Read Memory').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) memory = first;
    else if (Array.isArray(first.memory)) memory = first.memory;
    else memory = items.map(i => i.json);
  }
} catch(e) {}

const agentList = registry.length > 0
  ? registry.map(a => `- ${a.name}: ${a.description} (good for: ${a.good_for || ''})`).join('\n')
  : 'No agents yet';

const recentMemory = memory.slice(-6)
  .map(m => `[${m.agent}] ${m.task} → ${(m.result || '').substring(0, 80)}`)
  .join('\n') || 'None';

const conversationHistory = memory.slice(-10)
  .map(m => {
    const assistant = m.agent === 'chitchat' ? 'Assistant' : `Assistant [${m.agent}]`;
    return `User: ${m.task}\n${assistant}: ${(m.result || '').substring(0, 300)}`;
  })
  .join('\n\n') || '';

return [{ json: { userMessage, chatId, agentList, recentMemory, conversationHistory } }];

const text = $input.item.json.response || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { action: 'chitchat', agent_name: null };
}
const userMessage = $('Prepare Data').first().json.userMessage;
const chatId = $('Prepare Data').first().json.chatId;
return [{ json: {
  action: parsed.action || 'chitchat',
  agent_name: parsed.agent_name || null,
  userMessage,
  chatId
}}];

